else:
  data = &#039;&#039;&#039;
var url = &quot;&#039;&#039;&#039;+str(sys.argv[1])+&#039;&#039;&#039;&quot;;
if (url.endsWith(&quot;/&quot;)) {
 url = url.slice(0, -1);
}
var urlWithoutLog = url.split(&quot;/&quot;).slice(0, -1).join(&quot;/&quot;);
